1	import { quote, claim } from "./claim-office.js";
2	
3	export function runScenario(scenario: any): { results: unknown[] } {
4	  const results: unknown[] = [];
5	  let quoteCount = 0;
6	  for (const step of scenario.steps) {
7	    if (step.op === "quote") {
8	      const premium = quote({
9	        customer: {
10	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
11	          previousContracts: quoteCount,
12	        },
13	        items: step.items,
14	      });
15	      results.push({ premium });
16	      quoteCount++;
17	    } else if (step.op === "claim") {
18	      const policyStep = scenario.steps[step.policy];
19	      const { payout, remainingCap } = claim({
20	        items: policyStep.items,
21	        incident: step.incident,
22	      });
23	      results.push({ payout, remainingCap });
24	    }
25	  }
26	  return { results };
27	}
